solution_code:
#include <iostream>

class Base {
public:
    virtual void greet() const { std::cout << "Base::greet\n"; }
};

class Derived : public Base {
public:
    void greet() const override { std::cout << "Derived::greet\n"; }
};

int main() {
    Derived d;
    Base* p = &d;

    d.Base::greet();   // early binding
    p->Base::greet();  // early binding via scope resolution
    p->greet();        // late binding

    return 0;
}

