solution_code:
#include <iostream>

class Logger {
public:
    virtual void run() const { std::cout << "Base log\n"; }
};

class Task : public Logger {
public:
    void run() const override {
        Logger::run();   // explicit early binding to base
        std::cout << "Derived action\n";
    }
};

int main() {
    Task t;
    Logger* p = &t;
    p->run();
    return 0;
}
